81	/// to handle requests. Thus, only `Router<()>` (i.e. without missing state) can
82	/// be passed to [`serve`]. See [`Router::with_state`] for more details.
83	///
84	/// [`serve`]: crate::serve()
85	#[must_use]
86	pub struct Router<S = ()> {
87	    inner: Arc<RouterInner<S>>,
88	}
