98	struct RouterInner<S> {
99	    path_router: PathRouter<S>,
100	    default_fallback: bool,
101	    catch_all_fallback: Fallback<S>,
102	}
103	
104	impl<S> Default for Router<S>
105	where
106	    S: Clone + Send + Sync + 'static,
