129	macro_rules! map_inner {
130	    ( $self_:ident, $inner:pat_param => $expr:expr) => {
131	        #[allow(redundant_semicolons)]
132	        {
133	            let $inner = $self_.into_inner();
134	            Router {
135	                inner: Arc::new($expr),
136	            }
137	        }
138	    };
139	}
140	
141	macro_rules! tap_inner {
142	    ( $self_:ident, mut $inner:ident => { $($stmt:stmt)* } ) => {
143	        #[allow(redundant_semicolons)]
144	        {
145	            let mut $inner = $self_.into_inner();
146	            $($stmt)*;
