154	impl<S> Router<S>
155	where
156	    S: Clone + Send + Sync + 'static,
157	{
158	    /// Create a new `Router`.
159	    ///
160	    /// Unless you add additional routes this will respond with `404 Not Found` to
161	    /// all requests.
162	    pub fn new() -> Self {
163	        Self {
164	            inner: Arc::new(RouterInner {
165	                path_router: Default::default(),
166	                default_fallback: true,
167	                catch_all_fallback: Fallback::Default(Route::new(NotFound)),
168	            }),
169	        }
170	    }
171	
172	    fn into_inner(self) -> RouterInner<S> {
173	        match Arc::try_unwrap(self.inner) {
174	            Ok(inner) => inner,
175	            Err(arc) => RouterInner {
176	                path_router: arc.path_router.clone(),
177	                default_fallback: arc.default_fallback,
178	                catch_all_fallback: arc.catch_all_fallback.clone(),
179	            },
180	        }
181	    }
