183	    #[doc = include_str!("../docs/routing/without_v07_checks.md")]
184	    pub fn without_v07_checks(self) -> Self {
185	        tap_inner!(self, mut this => {
186	            this.path_router.without_v07_checks();
187	        })
188	    }
