191	    #[track_caller]
192	    pub fn route(self, path: &str, method_router: MethodRouter<S>) -> Self {
193	        tap_inner!(self, mut this => {
194	            panic_on_err!(this.path_router.route(path, method_router));
195	        })
196	    }
197	
198	    #[doc = include_str!("../docs/routing/route_service.md")]
199	    pub fn route_service<T>(self, path: &str, service: T) -> Self
200	    where
201	        T: Service<Request, Error = Infallible> + Clone + Send + Sync + 'static,
202	        T::Response: IntoResponse,
203	        T::Future: Send + 'static,
204	    {
205	        let Err(service) = try_downcast::<Self, _>(service) else {
206	            panic!(
207	                "Invalid route: `Router::route_service` cannot be used with `Router`s. \
208	                Use `Router::nest` instead"
209	            );
210	        };
211	
212	        tap_inner!(self, mut this => {
213	            panic_on_err!(this.path_router.route_service(path, service));
214	        })
215	    }
216	
217	    #[doc = include_str!("../docs/routing/nest.md")]
218	    #[doc(alias = "scope")] // Some other libs like actix-web use this term
219	    #[track_caller]
220	    pub fn nest(self, path: &str, router: Self) -> Self {
221	        if path.is_empty() || path == "/" {
222	            panic!("Nesting at the root is no longer supported. Use merge instead.");
223	        }
224	
225	        let RouterInner {
226	            path_router,
227	            default_fallback: _,
228	            // we don't need to inherit the catch-all fallback. It is only used for CONNECT
229	            // requests with an empty path. If we were to inherit the catch-all fallback
230	            // it would end up matching `/{path}/*` which doesn't match empty paths.
231	            catch_all_fallback: _,
232	        } = router.into_inner();
233	
234	        tap_inner!(self, mut this => {
235	            panic_on_err!(this.path_router.nest(path, path_router));
236	        })
237	    }
238	
239	    /// Like [`nest`](Self::nest), but accepts an arbitrary `Service`.
240	    #[track_caller]
241	    pub fn nest_service<T>(self, path: &str, service: T) -> Self
242	    where
243	        T: Service<Request, Error = Infallible> + Clone + Send + Sync + 'static,
244	        T::Response: IntoResponse,
245	        T::Future: Send + 'static,
246	    {
247	        if path.is_empty() || path == "/" {
248	            panic!("Nesting at the root is no longer supported. Use fallback_service instead.");
249	        }
250	
251	        tap_inner!(self, mut this => {
252	            panic_on_err!(this.path_router.nest_service(path, service));
253	        })
254	    }
255	
256	    #[doc = include_str!("../docs/routing/merge.md")]
257	    #[track_caller]
258	    pub fn merge<R>(self, other: R) -> Self
259	    where
260	        R: Into<Self>,
261	    {
262	        let other: Self = other.into();
263	        let RouterInner {
264	            path_router,
265	            default_fallback,
266	            catch_all_fallback,
267	        } = other.into_inner();
268	
269	        map_inner!(self, mut this => {
270	            match (this.default_fallback, default_fallback) {
271	                // other has a default fallback
272	                // use the one from other
273	                (_, true) => {}
274	                // this has default fallback, other has a custom fallback
275	                (true, false) => {
276	                    this.default_fallback = false;
277	                }
278	                // both have a custom fallback, not allowed
279	                (false, false) => {
280	                    panic!("Cannot merge two `Router`s that both have a fallback")
281	                }
282	            };
283	
284	            panic_on_err!(this.path_router.merge(path_router));
285	
286	            this.catch_all_fallback = this
287	                .catch_all_fallback
288	                .merge(catch_all_fallback)
289	                .unwrap_or_else(|| panic!("Cannot merge two `Router`s that both have a fallback"));
290	
291	            this
292	        })
293	    }
