295	    #[doc = include_str!("../docs/routing/layer.md")]
296	    pub fn layer<L>(self, layer: L) -> Self
297	    where
298	        L: Layer<Route> + Clone + Send + Sync + 'static,
299	        L::Service: Service<Request> + Clone + Send + Sync + 'static,
300	        <L::Service as Service<Request>>::Response: IntoResponse + 'static,
301	        <L::Service as Service<Request>>::Error: Into<Infallible> + 'static,
302	        <L::Service as Service<Request>>::Future: Send + 'static,
303	    {
304	        map_inner!(self, this => RouterInner {
305	            path_router: this.path_router.layer(layer.clone()),
306	            default_fallback: this.default_fallback,
307	            catch_all_fallback: this.catch_all_fallback.map(|route| route.layer(layer)),
308	        })
309	    }
310	
311	    #[doc = include_str!("../docs/routing/route_layer.md")]
312	    #[track_caller]
313	    pub fn route_layer<L>(self, layer: L) -> Self
314	    where
315	        L: Layer<Route> + Clone + Send + Sync + 'static,
316	        L::Service: Service<Request> + Clone + Send + Sync + 'static,
317	        <L::Service as Service<Request>>::Response: IntoResponse + 'static,
318	        <L::Service as Service<Request>>::Error: Into<Infallible> + 'static,
319	        <L::Service as Service<Request>>::Future: Send + 'static,
320	    {
321	        map_inner!(self, this => RouterInner {
322	            path_router: this.path_router.route_layer(layer),
323	            default_fallback: this.default_fallback,
324	            catch_all_fallback: this.catch_all_fallback,
325	        })
326	    }
327	
328	    /// True if the router currently has at least one route added.
329	    #[must_use]
330	    pub fn has_routes(&self) -> bool {
331	        self.inner.path_router.has_routes()
332	    }
333	
334	    #[track_caller]
335	    #[doc = include_str!("../docs/routing/fallback.md")]
336	    pub fn fallback<H, T>(self, handler: H) -> Self
337	    where
338	        H: Handler<T, S>,
339	        T: 'static,
340	    {
341	        tap_inner!(self, mut this => {
342	            this.catch_all_fallback =
343	                Fallback::BoxedHandler(BoxedIntoRoute::from_handler(handler.clone()));
344	        })
345	        .fallback_endpoint(Endpoint::MethodRouter(any(handler)))
346	    }
347	
348	    /// Add a fallback [`Service`] to the router.
349	    ///
350	    /// See [`Router::fallback`] for more details.
351	    pub fn fallback_service<T>(self, service: T) -> Self
352	    where
353	        T: Service<Request, Error = Infallible> + Clone + Send + Sync + 'static,
354	        T::Response: IntoResponse,
355	        T::Future: Send + 'static,
356	    {
357	        let route = Route::new(service);
358	        tap_inner!(self, mut this => {
359	            this.catch_all_fallback = Fallback::Service(route.clone());
360	        })
361	        .fallback_endpoint(Endpoint::Route(route))
362	    }
363	
364	    #[doc = include_str!("../docs/routing/method_not_allowed_fallback.md")]
365	    #[allow(clippy::needless_pass_by_value)]
366	    pub fn method_not_allowed_fallback<H, T>(self, handler: H) -> Self
367	    where
368	        H: Handler<T, S>,
369	        T: 'static,
370	    {
371	        tap_inner!(self, mut this => {
372	            this.path_router
373	                .method_not_allowed_fallback(&handler);
374	        })
375	    }
376	
377	    /// Reset the fallback to its default.
378	    ///
379	    /// Useful to merge two routers with fallbacks, as [`merge`] doesn't allow
380	    /// both routers to have an explicit fallback. Use this method to remove the
381	    /// one you want to discard before merging.
382	    ///
383	    /// [`merge`]: Self::merge
384	    pub fn reset_fallback(self) -> Self {
385	        tap_inner!(self, mut this => {
386	            this.default_fallback = true;
387	            this.catch_all_fallback = Fallback::Default(Route::new(NotFound));
388	        })
389	    }
390	
391	    fn fallback_endpoint(self, endpoint: Endpoint<S>) -> Self {
392	        // TODO make this better.
393	        // We need the returned `Service` to be `Clone` and the function inside `service_fn` to be
394	        // `FnMut` so instead of just using the owned service, we do this trick with `Option`. We
395	        // know this will be called just once so it's fine. We're doing that so that we avoid one
396	        // clone inside `oneshot_inner` so that the `Router` and subsequently the `State` is not
397	        // cloned too much.
398	        tap_inner!(self, mut this => {
399	            _ = this.path_router.route_endpoint(
400	                "/",
401	                endpoint.clone().layer(
402	                    layer_fn(
403	                        |service: Route| {
404	                            let mut service = Some(service);
405	                            service_fn(
406	                                #[cfg_attr(not(feature = "matched-path"), allow(unused_mut))]
407	                                move |mut request: Request| {
408	                                    #[cfg(feature = "matched-path")]
409	                                    request.extensions_mut().remove::<MatchedPath>();
410	                                    let route = take_route_or_internal_error(&mut service);
411	                                    route.oneshot_inner_owned(request)
412	                                }
413	                            )
414	                        }
415	                    )
416	                )
417	            );
418	
419	            _ = this.path_router.route_endpoint(
420	                FALLBACK_PARAM_PATH,
421	                endpoint.layer(
422	                    layer_fn(
423	                        |service: Route| {
424	                            let mut service = Some(service);
425	                            service_fn(
426	                                #[cfg_attr(not(feature = "matched-path"), allow(unused_mut))]
427	                                move |mut request: Request| {
428	                                    #[cfg(feature = "matched-path")]
429	                                    request.extensions_mut().remove::<MatchedPath>();
430	                                    let route = take_route_or_internal_error(&mut service);
431	                                    route.oneshot_inner_owned(request)
432	                                }
433	                            )
434	                        }
435	                    )
436	                )
437	            );
438	
439	            this.default_fallback = false;
440	        })
441	    }
442	
443	    #[doc = include_str!("../docs/routing/with_state.md")]
444	    pub fn with_state<S2>(self, state: S) -> Router<S2> {
445	        map_inner!(self, this => RouterInner {
446	            path_router: this.path_router.with_state(state.clone()),
447	            default_fallback: this.default_fallback,
448	            catch_all_fallback: this.catch_all_fallback.with_state(state),
449	        })
450	    }
451	
452	    pub(crate) fn call_with_state(&self, req: Request, state: S) -> RouteFuture<Infallible> {
453	        let (req, state) = match self.inner.path_router.call_with_state(req, state) {
454	            Ok(future) => return future,
455	            Err((req, state)) => (req, state),
456	        };
457	
458	        self.inner
459	            .catch_all_fallback
460	            .clone()
461	            .call_with_state(req, state)
462	    }
463	
464	    /// Convert the router into a borrowed [`Service`] with a fixed request body type, to aid type
465	    /// inference.
466	    ///
467	    /// In some cases when calling methods from [`tower::ServiceExt`] on a [`Router`] you might get
468	    /// type inference errors along the lines of
469	    ///
470	    /// ```not_rust
471	    /// let response = router.ready().await?.call(request).await?;
472	    ///                       ^^^^^ cannot infer type for type parameter `B`
473	    /// ```
474	    ///
475	    /// This happens because `Router` implements [`Service`] with `impl<B> Service<Request<B>> for Router<()>`.
476	    ///
477	    /// For example:
478	    ///
479	    /// ```compile_fail
480	    /// use axum::{
481	    ///     Router,
482	    ///     routing::get,
483	    ///     http::Request,
484	    ///     body::Body,
485	    /// };
486	    /// use tower::{Service, ServiceExt};
487	    ///
488	    /// # async fn async_main() -> Result<(), Box<dyn std::error::Error>> {
489	    /// let mut router = Router::new().route("/", get(|| async {}));
490	    /// let request = Request::new(Body::empty());
491	    /// let response = router.ready().await?.call(request).await?;
492	    /// # Ok(())
493	    /// # }
494	    /// ```
495	    ///
496	    /// Calling `Router::as_service` fixes that:
497	    ///
498	    /// ```
499	    /// use axum::{
500	    ///     Router,
