711	    Default(Route<E>),
712	    Service(Route<E>),
713	    BoxedHandler(BoxedIntoRoute<S, E>),
714	}
715	
716	impl<S, E> Fallback<S, E>
717	where
718	    S: Clone,
719	{
720	    fn merge(self, other: Self) -> Option<Self> {
721	        match (self, other) {
722	            // If either are `Default`, return the opposite one.
723	            (Self::Default(_), pick) | (pick, Self::Default(_)) => Some(pick),
724	            // Otherwise, return None
725	            _ => None,
726	        }
727	    }
728	
729	    fn map<F, E2>(self, f: F) -> Fallback<S, E2>
730	    where
731	        S: 'static,
732	        E: 'static,
733	        F: FnOnce(Route<E>) -> Route<E2> + Clone + Send + Sync + 'static,
734	        E2: 'static,
735	    {
736	        match self {
737	            Self::Default(route) => Fallback::Default(f(route)),
738	            Self::Service(route) => Fallback::Service(f(route)),
739	            Self::BoxedHandler(handler) => Fallback::BoxedHandler(handler.map(f)),
740	        }
741	    }
742	
743	    fn with_state<S2>(self, state: S) -> Fallback<S2, E> {
744	        match self {
745	            Self::Default(route) => Fallback::Default(route),
746	            Self::Service(route) => Fallback::Service(route),
747	            Self::BoxedHandler(handler) => Fallback::Service(handler.into_route(state)),
748	        }
749	    }
750	
751	    fn call_with_state(self, req: Request, state: S) -> RouteFuture<E> {
752	        match self {
753	            Self::Default(route) | Self::Service(route) => route.oneshot_inner_owned(req),
754	            Self::BoxedHandler(handler) => {
755	                let route = handler.into_route(state);
756	                route.oneshot_inner_owned(req)
757	            }
758	        }
759	    }
760	
761	    fn is_default(&self) -> bool {
762	        matches!(self, Self::Default(..))
763	    }
764	}
