559	async fn handle_connection<L, M, S, B, E>(
560	    make_service: &mut M,
561	    signal_tx: &watch::Sender<()>,
562	    close_rx: &watch::Receiver<()>,
563	    io: <L as Listener>::Io,
564	    remote_addr: <L as Listener>::Addr,
565	    executor: &E,
566	) where
567	    L: Listener,
568	    L::Addr: Debug,
569	    M: for<'a> Service<IncomingStream<'a, L>, Error = Infallible, Response = S> + Send + 'static,
570	    for<'a> <M as Service<IncomingStream<'a, L>>>::Future: Send,
571	    S: Service<Request, Response = Response<B>, Error = Infallible> + Clone + Send + 'static,
572	    S::Future: Send,
573	    B: HttpBody + Send + 'static,
574	    B::Data: Send,
575	    B::Error: Into<Box<dyn StdError + Send + Sync>>,
576	    E: Executor,
577	{
578	    let io = TokioIo::new(io);
579	
580	    trace!("connection {remote_addr:?} accepted");
581	
582	    make_service
583	        .ready()
584	        .await
585	        .unwrap_or_else(|err| match err {});
586	
587	    let tower_service = make_service
588	        .call(IncomingStream {
589	            io: &io,
590	            remote_addr,
591	        })
592	        .await
593	        .unwrap_or_else(|err| match err {})
594	        .map_request(|req: Request<Incoming>| req.map(Body::new));
595	
596	    let hyper_service = TowerToHyperService::new(tower_service);
597	    let signal_tx = signal_tx.clone();
598	    let close_rx = close_rx.clone();
599	
600	    let hyper_executor = HyperExecutor(executor.clone());
601	    executor.execute(async move {
602	        #[allow(unused_mut)]
603	        let mut builder = Builder::new(hyper_executor);
604	
605	        // Enable Hyper's default HTTP/1 request header timeout.
606	        #[cfg(feature = "http1")]
607	        builder.http1().timer(TokioTimer::new());
608	
609	        // CONNECT protocol needed for HTTP/2 websockets
610	        #[cfg(feature = "http2")]
611	        builder.http2().enable_connect_protocol();
612	
613	        let mut conn = pin!(builder.serve_connection_with_upgrades(io, hyper_service));
614	        let mut signal_closed = pin!(signal_tx.closed().fuse());
615	
616	        loop {
617	            tokio::select! {
618	                result = conn.as_mut() => {
619	                    if let Err(_err) = result {
620	                        trace!("failed to serve connection: {_err:#}");
621	                    }
622	                    break;
623	                }
624	                _ = &mut signal_closed => {
625	                    trace!("signal received in task, starting graceful shutdown");
626	                    conn.as_mut().graceful_shutdown();
627	                }
628	            }
629	        }
630	
631	        drop(close_rx);
632	    });
633	}
